import React, { useState } from "react";
import {
  useIncrementNumberMutation,
  useDecrementNumberMutation,
  useToggleBookingsMutation,
  useResetQueueMutation,
  useGetQueueStatusQuery,
} from "../state/services/queueApi";
import { useAuth } from "../hooks/useAuth";
import {
  FaPlus,
  FaMinus,
  FaPowerOff,
  FaTrash,
  FaChevronUp,
  FaChevronDown,
  FaCog,
} from "react-icons/fa";
import { motion, AnimatePresence } from "framer-motion";

const AdminControls: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [localError, setLocalError] = useState<string | null>(null);
  const { user } = useAuth();
  const { data: status } = useGetQueueStatusQuery();

  const [increment, { isLoading: isIncrementing }] =
    useIncrementNumberMutation();
  const [decrement, { isLoading: isDecrementing }] =
    useDecrementNumberMutation();
  const [toggleBookings, { isLoading: isToggling }] =
    useToggleBookingsMutation();
  const [resetQueue, { isLoading: isResetting }] = useResetQueueMutation();

  const handleIncrement = async () => {
    try {
      setLocalError(null);
      await increment().unwrap();
    } catch (err: any) {
      setLocalError(err.data?.message || "فشلت عملية الزيادة");
      setTimeout(() => setLocalError(null), 3000);
    }
  };

  const handleDecrement = async () => {
    try {
      setLocalError(null);
      await decrement().unwrap();
    } catch (err: any) {
      setLocalError(err.data?.message || "فشلت عملية النقصان");
      setTimeout(() => setLocalError(null), 3000);
    }
  };

  if (user?.role !== "admin") return null;

  return (
    <>
      {/* Error Message Tooltip */}
      <AnimatePresence>
        {localError && (
          <motion.div
            initial={{ opacity: 0, y: 10, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.9 }}
            className="fixed bottom-24 left-6 z-50 bg-red-600 text-white py-2 px-4 rounded-xl shadow-xl font-bold text-sm"
          >
            {localError}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Floating Toggle Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="fixed bottom-6 left-6 z-50 bg-gray-900 text-white py-3 px-6 rounded-full shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-3"
      >
        <FaCog
          className={`transition-transform duration-500 ${isOpen ? "rotate-90" : "rotate-0"} text-lg`}
        />
        <span className="font-bold text-sm whitespace-nowrap">
          {isOpen ? "إغلاق" : "لوحة التحكم"}
        </span>
        {isOpen ? <FaChevronDown size={12} /> : <FaChevronUp size={12} />}
      </button>

      {/* Admin Menu */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 50, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 50, scale: 0.9 }}
            className="fixed bottom-24 left-6 z-40 bg-white/95 backdrop-blur-md p-6 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] border border-gray-100 w-[calc(100%-3rem)] sm:w-80 overflow-hidden"
          >
            <div className="flex items-center justify-between mb-6 border-b border-gray-100 pb-4">
              <h3 className="font-black text-gray-900 text-lg">إدارة الدور</h3>
              <div className="bg-red-50 text-red-600 px-3 py-1 rounded-full text-xs font-bold">
                Admin Mode
              </div>
            </div>

            <div className="space-y-4">
              {/* Counter Controls */}
              <div className="grid grid-cols-2 gap-3">
                <button
                  onClick={handleIncrement}
                  disabled={isIncrementing}
                  className="bg-green-600 text-white font-bold py-4 px-4 rounded-2xl flex flex-col items-center justify-center gap-2 hover:bg-green-700 transition-all disabled:opacity-50 shadow-lg shadow-green-100"
                >
                  <FaPlus size={20} />
                  <span>التالي</span>
                </button>
                <button
                  onClick={handleDecrement}
                  disabled={
                    isDecrementing || !status || status.currentNumber === 0
                  }
                  className="bg-gray-100 text-gray-800 font-bold py-4 px-4 rounded-2xl flex flex-col items-center justify-center gap-2 hover:bg-gray-200 transition-all disabled:opacity-50"
                >
                  <FaMinus size={20} />
                  <span>السابق</span>
                </button>
              </div>

              {/* Status Toggle */}
              <button
                onClick={() => toggleBookings()}
                disabled={isToggling}
                className={`w-full font-bold py-4 px-4 rounded-2xl flex items-center justify-center gap-3 transition-all disabled:opacity-50 shadow-sm ${
                  status?.isBookingsOpen
                    ? "bg-orange-500 hover:bg-orange-600 text-white shadow-orange-100"
                    : "bg-emerald-50 hover:bg-emerald-100 text-emerald-700 border border-emerald-100"
                }`}
              >
                <FaPowerOff />
                {status?.isBookingsOpen ? "إيقاف الحجوزات" : "فتح الحجوزات"}
              </button>

              {/* Danger Zone */}
              <div className="pt-2 border-t border-gray-100 mt-2">
                <button
                  onClick={() => {
                    if (
                      window.confirm(
                        "هل أنت متأكد من تصفير الدور وحذف جميع الحجوزات؟",
                      )
                    ) {
                      resetQueue();
                    }
                  }}
                  disabled={isResetting}
                  className="w-full bg-red-50 text-red-600 font-bold py-3 px-4 rounded-xl flex items-center justify-center gap-2 hover:bg-red-100 transition-all disabled:opacity-50"
                >
                  <FaTrash size={14} />
                  <span className="text-sm">تصفير كافة البيانات</span>
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default AdminControls;

import React, { useState } from "react";
import {
  useAdminCreateTicketMutation,
  useGetQueueStatusQuery,
} from "../state/services/queueApi";
import { useAuth } from "../hooks/useAuth";
import {
  FaUserPlus,
  FaCheckCircle,
  FaChevronDown,
  FaChevronUp,
  FaTicketAlt,
} from "react-icons/fa";
import { motion, AnimatePresence } from "framer-motion";

const AdminTicketIssuer: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [customerName, setCustomerName] = useState("");
  const [localError, setLocalError] = useState<string | null>(null);
  const [showSuccess, setShowSuccess] = useState(false);
  const { user } = useAuth();
  const { data: status } = useGetQueueStatusQuery();
  const [adminCreateTicket, { isLoading: isCreatingTicket }] =
    useAdminCreateTicketMutation();

  const handleIssueTicket = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      setLocalError(null);
      await adminCreateTicket({
        customerName: customerName.trim() || undefined,
      }).unwrap();
      setCustomerName("");
      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 2000);
      setIsOpen(false);
    } catch (err: any) {
      setLocalError(err.data?.message || "فشل إنشاء التذكرة");
      setTimeout(() => setLocalError(null), 3000);
    }
  };

  if (user?.role !== "admin") return null;

  return (
    <>
      {/* Success/Error Alerts */}
      <AnimatePresence>
        {localError && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
            className="fixed bottom-40 right-6 z-50 bg-red-600 text-white py-2 px-4 rounded-xl shadow-xl font-bold text-sm"
          >
            {localError}
          </motion.div>
        )}
        {showSuccess && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
            className="fixed bottom-40 right-6 z-50 bg-emerald-600 text-white py-2 px-4 rounded-xl shadow-xl font-bold text-sm flex items-center gap-2"
          >
            <FaCheckCircle />
            <span>تم إصدار التذكرة بنجاح</span>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Floating Button for Ticket Issuance */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="fixed bottom-6 right-6 z-50 bg-emerald-600 text-white py-3 px-6 rounded-full shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-3"
      >
        <FaUserPlus className="text-lg" />
        <span className="font-bold text-sm whitespace-nowrap">إصدار تذكرة</span>
        {isOpen ? <FaChevronDown size={12} /> : <FaChevronUp size={12} />}
      </button>

      {/* Issuance Panel */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 50, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 50, scale: 0.9 }}
            className="fixed bottom-24 right-6 z-40 bg-white/95 backdrop-blur-md p-6 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] border border-gray-100 w-[calc(100%-3rem)] sm:w-80"
          >
            <div className="flex items-center justify-between mb-6 border-b border-gray-100 pb-4">
              <div className="flex items-center gap-2">
                <div className="bg-emerald-100 text-emerald-600 p-2 rounded-lg">
                  <FaTicketAlt />
                </div>
                <h3 className="font-black text-gray-900 text-lg">
                  تذكرة فورية
                </h3>
              </div>
              <div className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-[10px] font-bold uppercase">
                Walk-in
              </div>
            </div>

            <form onSubmit={handleIssueTicket} className="space-y-4">
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase mb-1.5 block px-1">
                  اسم الزبون (اختياري)
                </label>
                <input
                  type="text"
                  value={customerName}
                  onChange={(e) => setCustomerName(e.target.value)}
                  placeholder="مثلاً: أحمد فؤاد..."
                  className="w-full bg-gray-50 border border-gray-200 py-3 px-4 rounded-2xl text-sm outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-medium"
                />
              </div>

              <button
                type="submit"
                disabled={isCreatingTicket || !status?.isBookingsOpen}
                className="w-full bg-emerald-600 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 hover:bg-emerald-700 transition-all disabled:opacity-50 shadow-lg shadow-emerald-100 mt-2"
              >
                {isCreatingTicket ? (
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : (
                  <>
                    <FaUserPlus />
                    <span>تأكيد الإصدار</span>
                  </>
                )}
              </button>

              {!status?.isBookingsOpen && (
                <p className="text-[10px] text-center text-orange-600 font-bold bg-orange-50 p-2 rounded-lg">
                  لا يمكن الإصدار حالياً لأن الحجوزات مغلقة
                </p>
              )}
            </form>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default AdminTicketIssuer;

import React, { useState } from "react";
import {
  useGetAllTicketsQuery,
  useAdminRemoveTicketMutation,
} from "../state/services/queueApi";
import { FaSearch, FaTrashAlt, FaUserClock, FaEnvelope } from "react-icons/fa";
import { motion, AnimatePresence } from "framer-motion";

const AdminTicketList: React.FC = () => {
  const { data: tickets, isLoading, error } = useGetAllTicketsQuery();
  const [removeTicket, { isLoading: isRemoving }] =
    useAdminRemoveTicketMutation();
  const [searchTerm, setSearchTerm] = useState("");

  const handleRemove = async (ticketId: string) => {
    if (window.confirm("هل أنت متأكد من رغبتك في حذف هذه التذكرة؟")) {
      try {
        await removeTicket(ticketId).unwrap();
      } catch (err) {
        console.error("Failed to remove ticket:", err);
      }
    }
  };

  const filteredTickets = tickets?.filter((ticket) => {
    const isObject = ticket.userId && typeof ticket.userId === "object";
    const userEmail = isObject ? (ticket.userId as any).email || "" : "";
    const userName = isObject ? (ticket.userId as any).name || "" : "";
    const customerName = ticket.customerName || "";
    const searchLower = searchTerm.toLowerCase();

    return (
      userEmail.toLowerCase().includes(searchLower) ||
      userName.toLowerCase().includes(searchLower) ||
      customerName.toLowerCase().includes(searchLower) ||
      ticket.number.toString().includes(searchTerm)
    );
  });

  if (isLoading)
    return (
      <div className="p-4 text-center text-gray-500 animate-pulse">
        Loading tickets...
      </div>
    );
  if (error) return null;

  return (
    <div className="bg-white rounded-[2.5rem] shadow-2xl border border-gray-50 flex flex-col h-[600px] overflow-hidden">
      <div className="p-6 border-b border-gray-50">
        <h3 className="text-xl font-black text-gray-900 mb-4 flex items-center gap-2">
          <FaUserClock className="text-red-600" />
          قائمة الحجوزات النشطة
        </h3>

        {/* Search Bar */}
        <div className="relative">
          <FaSearch className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
          <input
            type="text"
            placeholder="البحث عبر البريد أو الرقم..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-gray-50 border border-transparent py-3 pl-11 pr-4 rounded-2xl text-sm outline-none focus:bg-white focus:border-red-100 focus:ring-4 focus:ring-red-500/5 transition-all"
          />
        </div>
      </div>

      <div className="grow overflow-y-auto p-4 space-y-3 custom-scrollbar">
        <AnimatePresence mode="popLayout">
          {filteredTickets?.length === 0 ? (
            <div className="text-center py-10 text-gray-400 font-medium">
              لا توجد نتائج تطابق بحثك
            </div>
          ) : (
            filteredTickets?.map((ticket) => (
              <motion.div
                key={ticket._id}
                layout
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, scale: 0.9 }}
                className={`p-4 rounded-3xl border flex items-center justify-between transition-all group ${
                  ticket.status === "called"
                    ? "bg-emerald-50 border-emerald-100"
                    : "bg-white border-gray-100 hover:border-red-100 hover:shadow-lg hover:shadow-red-500/5"
                }`}
              >
                <div className="flex items-center gap-4">
                  <div
                    className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg shadow-sm ${
                      ticket.status === "called"
                        ? "bg-emerald-500 text-white"
                        : "bg-gray-900 text-white"
                    }`}
                  >
                    {ticket.number}
                  </div>
                  <div>
                    <div className="font-black text-gray-900 truncate max-w-[150px]">
                      {ticket.createdByAdmin
                        ? ticket.customerName || "إصدار يدوي"
                        : typeof ticket.userId === "object"
                          ? ticket.userId?.name
                          : "مستخدم نظام"}
                    </div>
                    <div className="text-xs text-gray-500 font-bold flex items-center gap-1">
                      {ticket.createdByAdmin ? (
                        <span className="bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-md text-[10px] uppercase">
                          By Admin
                        </span>
                      ) : (
                        <>
                          <FaEnvelope className="text-[10px]" />
                          <span className="truncate max-w-[120px]">
                            {typeof ticket.userId === "object"
                              ? ticket.userId?.email
                              : "---"}
                          </span>
                        </>
                      )}
                    </div>
                  </div>
                </div>

                <button
                  onClick={() => handleRemove(ticket._id)}
                  disabled={isRemoving}
                  className="p-3 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all active:scale-90"
                  title="حذف التذكرة"
                >
                  <FaTrashAlt />
                </button>
              </motion.div>
            ))
          )}
        </AnimatePresence>
      </div>

      <div className="p-4 bg-gray-50 text-center border-t border-gray-100">
        <span className="text-xs font-black text-gray-400 uppercase tracking-widest">
          إجمالي الحجوزات: {filteredTickets?.length || 0}
        </span>
      </div>
    </div>
  );
};

export default AdminTicketList;

import React, { useState } from "react";
import { Link } from "react-router-dom";
import {
  FaUserPlus,
  FaTicketAlt,
  FaClock,
  FaChartLine,
  FaDesktop,
  FaCheckCircle,
  FaAngleRight,
  FaAngleLeft,
  FaGlobe,
  FaMobileAlt,
  FaSmile,
} from "react-icons/fa";
import { motion } from "framer-motion";
import Header from "../../components/Header";
import { useAuth } from "../../hooks/useAuth";

const Landing: React.FC = () => {
  const [lang, setLang] = useState<"ar" | "en">("ar");
  const { user } = useAuth();

  const content = {
    en: {
      dir: "ltr",
      welcome: "Welcome to Ahla Fawda",
      subtitle: "Electronic Queue Management System",
      description:
        "Save time, skip the line. Book your turn from home and watch the real-time queue status from anywhere.",
      cta: user ? "Enter Queue Dashboard" : "Get Started Now",
